/**
 * Delegate for MimManager to use global listening for all listening.
 * @class GlobalListener
 * @memberof jibo.mim
 * @private
 */

    /**
     * Optional async cleanup function for listeners
     * @name jibo.mim.GlobalListener#cleanupHandler
     * @type {Function}
     * @param {Function} done Callback for notifying when cleaning up is completed
     * @static
     */

    /**
     * Sets the listen mode. On GlobalListener this is a no-op.
     * @method jibo.mim.GlobalListener#setMode
     * @param {string} mode Option from {jibo.mim.GlobalListener#ListenMode} to set the mode to.
     * @static
     */

    /**
     * Create a GlobalListener instance to use.
     * @method jibo.mim.GlobalListener#create
     * @param {any} options The listening options.
     * @param {string} rulePath The path to the rule file (currently .rule only).
     * @returns {GlobalListener} The GlobalListener instance.
     * @static
     */

    /**
     * Stop listening.
     * @param {Boolean} [unsubscribe] The listener should unsubscribe from the Global Listen Service.
     * @method jibo.mim.GlobalListener#stop
     */